import React, {createContext, type FC, type PropsWithChildren, useContext, useEffect, useRef, useState} from 'react';
import localeFiles from "../../locale";                               // built-in languages
import {addLocale, locale, localeOption} from "primereact/api";
import type {ILocaleContextProps, ILocaleContextValues} from "@lmb-it/kitsconcerto-types";


export const LocaleContext = createContext<ILocaleContextValues>({} as ILocaleContextValues);

const LocaleContextProvider: FC<PropsWithChildren<ILocaleContextProps>> = ({
                                                                               children,
                                                                               languages,
                                                                               defaultLanguage = 'en',
                                                                               onChangeLanguage
                                                                           }) => {

    const defaultLocal = useRef<string>("");

    const translationsKeys = useRef<string[]>([]);
    const [language, setLanguage] = useState<string>(defaultLanguage)
    const [isRTL, setIsRTL] = useState<boolean>(defaultLanguage == 'ar')

    const [refresh, setRefresh] = useState<Date>(new Date()) //this which get the initial language rendered


    useEffect(() => {
        if(defaultLocal.current == defaultLanguage) return;
        defaultLocal.current = defaultLanguage;

        changeLanguage(defaultLanguage)
    }, [defaultLanguage]);

    const isKeyExists = (key: string)=>{
        return translationsKeys.current.includes(key)
    }

    const setTranslations = () => {
        const translations: { [x: string]: any } = {};

        Object.entries(localeFiles).forEach(([key, obj])=>{
            translations[key]=obj;
        })

        languages?.forEach(item => {
            if (item.lang in localeFiles) {
                const key = item.lang as keyof typeof localeFiles;

                // Check if langs[key] is an object before spreading
                const langTranslations = typeof localeFiles[key] === 'object' ? localeFiles[key] : {};

                translations[item.lang] = {
                    ...langTranslations,
                    ...(item.translations || {}) // spread safely in case item.translations is undefined
                };
            } else {
                translations[item.lang] = { ...(item.translations || {}) };
            }
        });


        Object.entries(translations).forEach(([key, value]) => {
            addLocale(key, value);
        });

        translationsKeys.current = Object.keys(translations)
        setRefresh(new Date());
    };

    useEffect(() => {
        setTranslations()
        changeLanguage();
    }, []);

    const currentLanguage = (() => {
        const fromLocal = localStorage.getItem('currentLanguage')

        if (fromLocal != language) {
            localStorage.setItem('currentLanguage', language)
        }

        return language;
    })();


    const changeLanguage = (key: string | null = null) => {

        const lang = key ?? currentLanguage;
        onChangeLanguage && onChangeLanguage(lang)
        locale(lang)
        setLanguage(lang)
        setIsRTL(lang === 'ar')

        localStorage.setItem('currentLanguage', lang)

        setRefresh(new Date());

    }


    const firstLanguage = languages?.length ? languages[0]?.translations : {};
    const t = (key: keyof typeof firstLanguage | string, ...params: (number | string)[]) => {
        try {

            let found = localeOption(key.toString(), currentLanguage) ?? key;
            // console.log({key, found,currentLanguage})

            const placeholders = found.match(/:\w+/g) || [];

            placeholders.forEach((placeholder: string, index: number) => {
                found = found.replace(placeholder, params[index] || '');
            });


            return found
        } catch (e) {
            return key;
        }
    }


    return (
        <LocaleContext.Provider value={{
            changeLanguage,
            t,
            currentLanguage,
            isRTL,
            isKeyExists
        }}>
            {children}
        </LocaleContext.Provider>
    );
};

export default LocaleContextProvider;
